import{_ as a,o as t,c as e,ag as n}from"./chunks/framework.ePeAWSvT.js";const m=JSON.parse('{"title":"设计理念","description":"","frontmatter":{},"headers":[],"relativePath":"memory-bench/server/design.md","filePath":"memory-bench/server/design.md"}'),p={name:"memory-bench/server/design.md"};function i(l,s,o,r,d,h){return t(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="设计理念" tabindex="-1">设计理念 <a class="header-anchor" href="#设计理念" aria-label="Permalink to &quot;设计理念&quot;">​</a></h1><p>Memory Chat Server 是 Memory Bench 子项目的核心服务，为 AI 角色对话提供<strong>记忆增强</strong>能力。</p><h2 id="🎯-核心问题" tabindex="-1">🎯 核心问题 <a class="header-anchor" href="#🎯-核心问题" aria-label="Permalink to &quot;🎯 核心问题&quot;">​</a></h2><blockquote><p>AI 聊天机器人普遍存在&quot;金鱼记忆&quot;问题——每次对话都从零开始，不记得之前说过什么。</p></blockquote><p>Memory Chat Server 的目标是解决这个问题：让 AI 角色能<strong>真正记住</strong>与用户的交互。</p><h2 id="📐-职责分离-两个端点-两种哲学" tabindex="-1">📐 职责分离：两个端点，两种哲学 <a class="header-anchor" href="#📐-职责分离-两个端点-两种哲学" aria-label="Permalink to &quot;📐 职责分离：两个端点，两种哲学&quot;">​</a></h2><p>Server 同时服务两种完全不同的调用场景，因此拆分为两个端点，各有清晰的职责边界：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Memory Chat Server</span></span>
<span class="line"><span>├── /v1/chat/completions     ← 透明代理（router.py）</span></span>
<span class="line"><span>└── /memory/chat             ← 自治 Agent（chat_router.py）</span></span></code></pre></div><h3 id="透明代理-vs-自治-agent" tabindex="-1">透明代理 vs 自治 Agent <a class="header-anchor" href="#透明代理-vs-自治-agent" aria-label="Permalink to &quot;透明代理 vs 自治 Agent&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th><code>/v1/chat/completions</code></th><th><code>/memory/chat</code></th></tr></thead><tbody><tr><td>📋 <strong>角色</strong></td><td>透明代理</td><td>自治 Agent</td></tr><tr><td>🎯 <strong>原则</strong></td><td>调用方感知不到记忆层</td><td>Server 完全掌控 session</td></tr><tr><td>👤 <strong>调用方</strong></td><td><code>src/lab</code> Agent（有自己的 MCP、上下文管理）</td><td>AIChat 等轻量客户端</td></tr><tr><td>🧠 <strong>记忆</strong></td><td>仅注入到 system prompt 末尾</td><td>Server 管理对话历史 + 记忆注入</td></tr><tr><td>💬 <strong>上下文</strong></td><td>调用方负责</td><td>Server 负责（日期 JSON 持久化）</td></tr><tr><td>🔧 <strong>工具</strong></td><td>完整透传（tool_use/tool_result 不过滤）</td><td>内置 READ/WRITE/EDIT/SEARCH</td></tr><tr><td>📡 <strong>协议</strong></td><td>OpenAI 兼容</td><td>简化自定义协议</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">为什么不合并成一个？</p><p>因为两种调用方的需求本质不同。<code>src/lab</code> 的 Agent 已经有完整的工具调用栈（MCP client-server、多图处理），它只需要一个&quot;加了记忆的 LLM 代理&quot;。而 AIChat 是轻量客户端，需要 server 端帮它管理一切。</p><p>合并会导致两边都做不好：代理不够透明，自治不够彻底。</p></div><hr><h2 id="🧠-记忆架构" tabindex="-1">🧠 记忆架构 <a class="header-anchor" href="#🧠-记忆架构" aria-label="Permalink to &quot;🧠 记忆架构&quot;">​</a></h2><h3 id="mem0-记忆的存储与检索" tabindex="-1">mem0：记忆的存储与检索 <a class="header-anchor" href="#mem0-记忆的存储与检索" aria-label="Permalink to &quot;mem0：记忆的存储与检索&quot;">​</a></h3><p><a href="https://github.com/mem0ai/mem0" target="_blank" rel="noreferrer">mem0</a> 负责从对话中<strong>自动提取</strong>和<strong>语义检索</strong>记忆：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户消息 → mem0.search() → 相关记忆 → 注入 system prompt</span></span>
<span class="line"><span>                                          ↓</span></span>
<span class="line"><span>对话结束 → mem0.add() → 新记忆写入 ← 异步后台</span></span></code></pre></div><p><strong>关键设计决策</strong>：</p><ul><li>搜索结果注入到 system prompt <strong>末尾</strong>，不插入额外 message，不破坏 message 顺序</li><li>写回只记录 <code>user</code> + <code>assistant</code> 轮次，工具调用中间步骤不写入</li><li>事实提取使用自定义 prompt，区分 <code>[User]</code> 和 <code>[Agent]</code> 前缀</li></ul><h3 id="neo4j-记忆的图谱化" tabindex="-1">Neo4j：记忆的图谱化 <a class="header-anchor" href="#neo4j-记忆的图谱化" aria-label="Permalink to &quot;Neo4j：记忆的图谱化&quot;">​</a></h3><p>记忆不只是存起来——通过实时图谱管线，每条记忆都被结构化为知识图谱节点：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mem0.add() 返回结果</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>claim_extractor.py → 提取 claim / entity</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>graph_writer.py → Cypher MERGE 写入 Neo4j</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>MemoryItem 节点 → 关联 Character / Scene / Conversation</span></span></code></pre></div><div class="tip custom-block github-alert"><p class="custom-block-title">图谱管线是可选的（\`--enable-graph\`），不影响基础对话功能。</p><p></p></div><hr><h2 id="🏗️-system-prompt-拼接" tabindex="-1">🏗️ System Prompt 拼接 <a class="header-anchor" href="#🏗️-system-prompt-拼接" aria-label="Permalink to &quot;🏗️ System Prompt 拼接&quot;">​</a></h2><p><code>/memory/chat</code> 端点不接受客户端传来的 system prompt，而是自己按以下公式拼接：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[persona]  base_persona.txt          ← 角色人设（身份、语言、风格）</span></span>
<span class="line"><span>+</span></span>
<span class="line"><span>[emotion]  emotion_system.txt        ← EMOTION 格式说明</span></span>
<span class="line"><span>+</span></span>
<span class="line"><span>[tool]     tool_definitions.txt      ← 工具定义 + 文件路径认知（可选）</span></span>
<span class="line"><span>+</span></span>
<span class="line"><span>[diary]    recent_summary.txt        ← 近期日记总结（可选）</span></span>
<span class="line"><span>=</span></span>
<span class="line"><span>完整 system prompt</span></span></code></pre></div><p><strong>为什么不让客户端传 system prompt？</strong></p><ul><li>同一个 session 里重复注入多份 system prompt 会污染上下文</li><li>无法统一控制记忆注入的时机和格式</li><li>Server 端拼接可以保证一致性</li></ul><hr><h2 id="🛡️-安全模型-分级授权" tabindex="-1">🛡️ 安全模型：分级授权 <a class="header-anchor" href="#🛡️-安全模型-分级授权" aria-label="Permalink to &quot;🛡️ 安全模型：分级授权&quot;">​</a></h2><p>自治 Agent 端点赋予了 LLM 文件操作能力，但严格控制了权限边界：</p><h3 id="写入-限定在-memory-bench-内部" tabindex="-1">写入：限定在 <code>memory_bench/</code> 内部 <a class="header-anchor" href="#写入-限定在-memory-bench-内部" aria-label="Permalink to &quot;写入：限定在 \`memory_bench/\` 内部&quot;">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>默认路径</th><th style="text-align:center;">是否需要指定路径</th></tr></thead><tbody><tr><td>写日记</td><td><code>memory_bench/data/diary/YYYY-MM-DD.md</code></td><td style="text-align:center;">❌</td></tr><tr><td>修改 prompt</td><td><code>memory_bench/server/prompts/...</code></td><td style="text-align:center;">❌</td></tr><tr><td>&quot;保存起来&quot;</td><td><code>memory_bench/data/saved/&lt;auto_name&gt;.md</code></td><td style="text-align:center;">❌</td></tr><tr><td>写特定文件</td><td>用户指定路径</td><td style="text-align:center;">✅（必须在 memory_bench 内）</td></tr></tbody></table><h3 id="读取-分层级" tabindex="-1">读取：分层级 <a class="header-anchor" href="#读取-分层级" aria-label="Permalink to &quot;读取：分层级&quot;">​</a></h3><table tabindex="0"><thead><tr><th>层级</th><th>范围</th><th>说明</th></tr></thead><tbody><tr><td>Level 1</td><td><code>memory_bench/</code> 预设位置</td><td>无需路径，按 purpose 自动定位</td></tr><tr><td>Level 2</td><td>整个 workspace（只读）</td><td>可以读取仓库任何文件作为参考</td></tr></tbody></table><div class="warning custom-block github-alert"><p class="custom-block-title">LLM 不能修改 \`memory_bench/\` 外的任何文件。如果需要修改外部文件，会告诉用户手动操作。</p><p></p></div><hr><h2 id="📦-对话持久化" tabindex="-1">📦 对话持久化 <a class="header-anchor" href="#📦-对话持久化" aria-label="Permalink to &quot;📦 对话持久化&quot;">​</a></h2><p><code>/memory/chat</code> 的对话历史以日期为单位存储为 JSON 文件：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>memory_bench/conversations/</span></span>
<span class="line"><span>├── 2026-03-03.json</span></span>
<span class="line"><span>├── 2026-03-04.json</span></span>
<span class="line"><span>└── 2026-03-04_02.json    ← 支持手动新开文件</span></span></code></pre></div><p>每个文件是一个 message 数组：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;role&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;user&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;content&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;你好&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;timestamp&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-03-04T08:00:00Z&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">},</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;role&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;assistant&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;content&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;你好呀！&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;timestamp&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-03-04T08:00:01Z&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p>日期 ID 与 Neo4j 的 <code>conv:YYYY-MM-DD</code> 节点对齐，确保对话和图谱的时间维度一致。</p><hr><h2 id="🔌-与-src-lab-的关系" tabindex="-1">🔌 与 <code>src/lab</code> 的关系 <a class="header-anchor" href="#🔌-与-src-lab-的关系" aria-label="Permalink to &quot;🔌 与 \`src/lab\` 的关系&quot;">​</a></h2><p><code>src/lab</code>（主项目）有完整的 Agent 栈。Memory Chat Server 不侵入这些，保持零耦合：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>src/lab Agent</span></span>
<span class="line"><span>  │  调用 /v1/chat/completions（换个 base_url 即可）</span></span>
<span class="line"><span>  │  Agent 完全不知道 memory_bench 的存在</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>Memory Chat Server</span></span>
<span class="line"><span>  │  注入记忆 → 转发 LLM → 异步写回</span></span>
<span class="line"><span>  ▼</span></span>
<span class="line"><span>LLM Provider (OpenAI / OpenRouter / ...)</span></span></code></pre></div><p><strong>约定</strong>：</p><ul><li><code>src/lab</code> Agent 只调透明代理端点，不感知内部实现</li><li>两个端点<strong>不共享</strong> session 状态</li><li>共用同一个 mem0 实例和 Neo4j graph pipeline（通过 <code>ServerState</code>）</li><li>配置隔离：memory_bench 的配置来自 <code>.env.benchmark</code>，不读取 <code>config/lab.toml</code></li></ul><hr><h2 id="📁-代码结构" tabindex="-1">📁 代码结构 <a class="header-anchor" href="#📁-代码结构" aria-label="Permalink to &quot;📁 代码结构&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>memory_bench/server/</span></span>
<span class="line"><span>├── chat_server.py          # 独立启动器（CLI + uvicorn）</span></span>
<span class="line"><span>├── startup.py              # 初始化逻辑（mem0 / OpenAI / 图谱管线）</span></span>
<span class="line"><span>├── router.py               # 透明代理端点（/v1/chat/completions）</span></span>
<span class="line"><span>├── chat_router.py          # 自治 Agent 端点（/memory/chat）</span></span>
<span class="line"><span>├── conversation_store.py   # 日期 JSON 对话持久化</span></span>
<span class="line"><span>├── claim_extractor.py      # LLM Claim 抽取</span></span>
<span class="line"><span>├── graph_writer.py         # Neo4j Cypher 写入</span></span>
<span class="line"><span>├── neo4j_queries.py        # Cypher 语句模板</span></span>
<span class="line"><span>├── prompts/                # System prompt 模块化文件</span></span>
<span class="line"><span>│   ├── emotion/</span></span>
<span class="line"><span>│   ├── tools/</span></span>
<span class="line"><span>│   └── diary/</span></span>
<span class="line"><span>└── tools/                  # 内置工具实现</span></span>
<span class="line"><span>    ├── file_tools.py       # READ / WRITE / EDIT</span></span>
<span class="line"><span>    └── search_tools.py     # SEARCH</span></span></code></pre></div><hr><h2 id="📚-延伸阅读" tabindex="-1">📚 延伸阅读 <a class="header-anchor" href="#📚-延伸阅读" aria-label="Permalink to &quot;📚 延伸阅读&quot;">​</a></h2><ul><li><a href="./routes.html">路由与端点</a> — 两个端点的详细 API 文档</li><li><a href="https://github.com/XnneHangLab/XnneHangLab/issues/224" target="_blank" rel="noreferrer">Issue #224</a> — 原始设计讨论</li></ul>`,55)])])}const g=a(p,[["render",i]]);export{m as __pageData,g as default};
